#include <bits/stdc++.h>
#define int long long
using namespace std;
const int maxn = 500000;
const int INF = 1e18;
struct Edge {
	int Juli;
	int Zhi;
};
Edge a[maxn + 1];
int dp[maxn + 1];
int q[maxn + 1];
int n, d, k;
int l, r;
int ans = -1;
int sum;
void init () {
	cin >> n >> d >> k;
	for (int i = 1; i <= n; i++) {
		cin >> a[i].Juli;
		cin >> a[i].Zhi;
		if (a[i].Zhi > 0) {
			sum += a[i].Zhi;
		}
	}
	r = max (a[n].Juli, d);
	return;
}
int check (int Zuo, int You) {
	for (int j = 0; j <= n; j++) {
		dp[j] = -INF;
	}
    dp[0] = 0;
    memset (q, 0, sizeof (q));
    int tou = 1, wei = 0, j = 0;
    for (int i = 1; i <= n; i++) {
        while (a[i].Juli - a[j].Juli >= Zuo && j < i) {
            if (dp[j] != -INF) {
                while (tou <= wei && dp[q[wei]] <= dp[j]) {
                	wei--;
				}
                q[++wei] = j;
            }
            j++;
        }
        while (tou <= wei && a[i].Juli - a[q[tou]].Juli > You) {
        	tou++;
        }
        if (tou <= wei) {
        	dp[i] = dp[q[tou]] + a[i].Zhi;
		}
    }
    int num = -INF;
    for (int i = 1; i <= n; i++) {
    	if (dp[i] > num) {
    		num = dp[i];
		}
	}
    return num;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	init ();
	if (sum < k) {
		cout << -1;
		return 0;
	}
	while (l <= r) {
		int mid = (l + r) / 2;
		int L;
		if (d - mid > 1) {
			L = d - mid;
		} else {
			L = 1;
		}
		int R = d + mid;
		int num = check (L, R);
		if (num < k) {
			l = mid + 1;
		} else {
			ans = mid;
			r = mid - 1;
		}
	}
	cout << ans;
	return 0;
}
